const en = require\('./apps/web/src/locales/en/site.json'\);
const ko = require\('./apps/web/src/locales/ko/site.json'\);
const vi = require\('./apps/web/src/locales/vi/site.json'\);
const getKeys = \(obj, prefix=''\) => Object.keys\(obj\).reduce\(\(acc, k\) => {
  const key = prefix ? prefix+'.'+k : k;
  if \(typeof obj[k] === 'object' && obj[k] !== null\) return [...acc, ...getKeys\(obj[k], key\)];
  return [...acc, key];
}, []\);
const enKeys = getKeys\(en\).sort\(\).join\(','\);
const koKeys = getKeys\(ko\).sort\(\).join\(','\);
const viKeys = getKeys\(vi\).sort\(\).join\(','\);
console.log\('en keys:', getKeys\(en\).length\);
console.log\('ko keys:', getKeys\(ko\).length\);
console.log\('vi keys:', getKeys\(vi\).length\);
console.log\('en===ko:', enKeys===koKeys\);
console.log\('en===vi:', enKeys===viKeys\);
")

